def safe_agent_loop(prompt, max_turns=5):
    for turn in range(max_turns):
        response = agent.invoke(prompt)

        verified = verify(
            response,
            rules={
                'loop_resolution': 'contains final decision (hire/no-hire/refer)',
                'ai_disclosure': 'includes "This evaluation powered by Llama AI"',
                'eeoc_compliant': 'no disparate impact language'
            }
        )

        if verified:
            return response

    raise Exception('Loop limit exceeded without resolution')

